+      const res = await fetch(`/api/documents/${id}`, {
+        method: "PATCH",
+        headers: { "Content-Type": "application/json" },
+        body: JSON.stringify(fields),
+      });
+      if (res.ok) {
+        const data = await res.json() as { doc: DocListItem };
+        // Update list item
+        setDocs(prev => prev.map(d => d._id === id ? { ...d, ...data.doc } : d));
