+                onChange={e => handlePipelineChange(e.target.value)}
+                style={{
+                  background: t.bgCard,
+                  border: `1px solid ${t.border}`,
+                  borderRadius: 6,
+                  padding: "2px 6px",
+                  fontSize: 9,
+                  color: t.textSec,
